CATS["اختر الجزء (الأول)"]={ic:"cat-juz.png",bg:"#E8D8C8",isJuz:true,slot:1};
CATS["اختر الجزء (الثاني)"]={ic:"cat-juz.png",bg:"#D8C8B8",isJuz:true,slot:2};
const CNAMES=Object.keys(CATS);
const LL=[{id:"h",ic:"🎯",n:"الحفرة"},{id:"c",ic:"📞",n:"اتصال"},{id:"t",ic:"✌",n:"جاوبين"},{id:"s",ic:"✋",n:"استريح"},{id:"x",ic:"🪤",n:"الفخ"}];
let sel=[],pll=[[],[]],teams=[],used=new Set(),cq=null,tInt=null,timer=0,turn=0,juz={1:null,2:null},gq={},phase='main',ms=null,adminCat=null,editIdx=null;
function show(id){document.querySelectorAll('.scr').forEach(s=>s.classList.remove('on'));document.getElementById(id).classList.add('on');if(id==='s-admin')renderAdmin();}
function shuf(a){return [...a].sort(()=>Math.random()-.5);}
function gcnt(cat){const d=CATS[cat];let qs;if(d.isJuz){const j=juz[d.slot];if(!j||!JUZ[j])return 0;qs=JUZ[j].q;}else qs=d.q;return Math.floor(Math.min(...[200,400,600].map(p=>qs.filter(q=>q.p===p).length))/2);}
function getQs(cat){const d=CATS[cat];if(d.isJuz){const j=juz[d.slot];return JUZ[j]?JUZ[j].q:[];}return d.q;}
function setQs(cat,qs){const d=CATS[cat];if(d.isJuz)JUZ[d.slot].q=qs;else d.q=qs;}
function pickGQ(){gq={};sel.forEach(c=>{const src=getQs(c);const p2=shuf(src.filter(q=>q.p===200)).slice(0,2);const p4=shuf(src.filter(q=>q.p===400)).slice(0,2);const p6=shuf(src.filter(q=>q.p===600)).slice(0,2);gq[c]=[...p2,...p4,...p6];});}
function buildGrid(){const ar=['٠','١','٢','٣','٤','٥','٦','٧','٨','٩'];document.getElementById('cat-grid').innerHTML=CNAMES.map(c=>{const s=sel.includes(c),n=sel.indexOf(c)+1,d=CATS[c];let body='';if(d.isJuz){const sl=d.slot,sj=juz[sl];let opts='<option value="">اختر جزءاً...</option>';Object.keys(JUZ).forEach(jn=>{const g=Math.floor(Math.min(...[200,400,600].map(p=>JUZ[jn].q.filter(q=>q.p===p).length))/2);opts+=`<option value="${jn}"${sj==jn?' selected':''}>${JUZ[jn].name} (${g} ألعاب)</option>`;});const g=sj?gcnt(c):0;body=`<div class="cat-img" style="background:${d.bg};height:62px"><img src="${d.ic}"></div><div style="padding:.28rem .22rem .32rem;text-align:center"><div style="font-size:.58rem;font-weight:700;color:#4A2A0A;margin-bottom:.25rem">${c}</div><select class="jsel" onclick="event.stopPropagation()" onchange="setJuz(${sl},this.value)">${opts}</select>${sj?`<div class="gtag">${g} ${g===1?'لعبة':'ألعاب'}</div>`:''}</div>`;}else{const g=gcnt(c);body=`<div class="cat-img" style="background:${d.bg}"><img src="${d.ic}"></div><div style="padding:.28rem .22rem .38rem;text-align:center"><div style="font-size:.62rem;font-weight:700;color:#4A2A0A;line-height:1.22">${c}</div><div class="gtag">${g} ${g===1?'لعبة':'ألعاب'}</div></div>`;}return`<div class="catcard${s?' sel':''}" onclick="togCat('${c}')">${s?`<div class="nb">${ar[n]||n}</div>`:''}${body}</div>`;}).join('');document.getElementById('selcount').textContent=(ar[sel.length]||sel.length)+' / ٦';document.getElementById('start-btn').disabled=sel.length!==6||!valJuz();}
function valJuz(){return sel.every(c=>!CATS[c].isJuz||juz[CATS[c].slot]!==null);}
function setJuz(sl,v){juz[sl]=v?parseInt(v):null;buildGrid();}
function togCat(c){if(sel.includes(c))sel=sel.filter(x=>x!==c);else if(sel.length<6)sel.push(c);buildGrid();}
function goSetup(){if(sel.length===6&&valJuz())show('s-setup');}
function renderAdmin(){const cats=CNAMES.filter(c=>!CATS[c].isJuz);const tot=cats.reduce((s,c)=>s+CATS[c].q.length,0)+Object.values(JUZ).reduce((s,j)=>s+j.q.length,0);document.getElementById('adm-stats').textContent=`📊 ${cats.length} قسم + جزءان • ${tot} سؤال`;let h=cats.map(c=>`<div class="arow" onclick="enterCat('${c}')"><div style="display:flex;align-items:center;gap:.5rem"><img class="aico" src="${CATS[c].ic}"><span style="font-weight:700;color:#4A2A0A;font-size:.82rem">${c}</span></div><div style="display:flex;gap:.28rem;align-items:center"><span class="gtag">${CATS[c].q.length} سؤال</span><span class="gtag" style="background:#D8E8C8;color:#3A6325">${gcnt(c)} ألعاب</span></div></div>`).join('');Object.entries(JUZ).forEach(([jn,jd])=>{const g=Math.floor(Math.min(...[200,400,600].map(p=>jd.q.filter(q=>q.p===p).length))/2);h+=`<div class="arow" onclick="enterJuz(${jn})"><div style="display:flex;align-items:center;gap:.5rem"><img class="aico" src="cat-juz.png"><span style="font-weight:700;color:#4A2A0A;font-size:.82rem">${jd.name}</span></div><div style="display:flex;gap:.28rem;align-items:center"><span class="gtag">${jd.q.length} سؤال</span><span class="gtag" style="background:#D8E8C8;color:#3A6325">${g} ألعاب</span></div></div>`;});document.getElementById('adm-cats').innerHTML=h;}
function enterCat(c){adminCat=c;document.getElementById('ac-ttl').textContent=c;renderCatQs();show('s-adm-cat');}
function enterJuz(j){adminCat='__j'+j;document.getElementById('ac-ttl').textContent=JUZ[j].name;renderCatQs();show('s-adm-cat');}
function getACQs(){return adminCat.startsWith('__j')?JUZ[adminCat.slice(3)].q:CATS[adminCat].q;}
function setACQs(qs){if(adminCat.startsWith('__j'))JUZ[adminCat.slice(3)].q=qs;else CATS[adminCat].q=qs;}
function renderCatQs(){const qs=getACQs();let h='';[200,400,600].forEach(p=>{const fl=qs.map((q,i)=>({q,i})).filter(({q})=>q.p===p);if(!fl.length)return;const col=p===200?'#5A8E3D':p===400?'#C05A20':'#9B2D2D';h+=`<div style="margin-bottom:.75rem"><div style="color:${col};font-weight:900;font-size:.76rem;margin-bottom:.32rem">${p} نقطة (${fl.length})</div>`;fl.forEach(({q,i})=>{const t=q.q.length>75?q.q.slice(0,75)+'...':q.q;h+=`<div class="aqrow"><span class="ppts" style="background:${col}">${p}${q.bo?' 🎁':''}</span><div class="aqtxt">${t}</div><button class="abtn" onclick="editQ(${i})">✎</button></div>`;});h+='</div>';});if(!qs.length)h='<p style="text-align:center;color:#A0826D;padding:1.8rem">لا توجد أسئلة</p>';document.getElementById('adm-qs').innerHTML=h;}
function newQ(){editIdx=null;document.getElementById('ae-ttl').textContent='إضافة سؤال جديد';document.getElementById('del-btn').style.display='none';clrForm();show('s-adm-edit');}
function editQ(i){editIdx=i;document.getElementById('ae-ttl').textContent='تعديل سؤال';document.getElementById('del-btn').style.display='block';const q=getACQs()[i];document.querySelector(`input[name="ept"][value="${q.p}"]`).checked=true;document.getElementById('e-q').value=q.q;document.getElementById('e-a').value=q.a;document.getElementById('e-ref').value=q.r;document.getElementById('e-src').value=q.s||'';if(q.bo){document.getElementById('e-bon').checked=true;document.getElementById('bon-fields').style.display='block';document.getElementById('e-bq').value=q.bo.q;document.getElementById('e-ba').value=q.bo.a;document.getElementById('e-bref').value=q.bo.r;}else{document.getElementById('e-bon').checked=false;document.getElementById('bon-fields').style.display='none';}show('s-adm-edit');}
function clrForm(){document.querySelector('input[name="ept"][value="200"]').checked=true;['e-q','e-a','e-ref','e-src','e-bq','e-ba','e-bref'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});document.getElementById('e-bon').checked=false;document.getElementById('bon-fields').style.display='none';}
function toggleBonus(){document.getElementById('bon-fields').style.display=document.getElementById('e-bon').checked?'block':'none';}
function cancelEdit(){show('s-adm-cat');}
function saveQ(){const p=parseInt(document.querySelector('input[name="ept"]:checked').value);const q=document.getElementById('e-q').value.trim(),a=document.getElementById('e-a').value.trim(),r=document.getElementById('e-ref').value.trim(),s=document.getElementById('e-src').value.trim();if(!q||!a||!r){alert('السؤال والإجابة والدليل مطلوبة');return;}const data={p,q,a,r,s};if(document.getElementById('e-bon').checked){const bq=document.getElementById('e-bq').value.trim(),ba=document.getElementById('e-ba').value.trim(),br=document.getElementById('e-bref').value.trim();if(bq&&ba&&br)data.bo={q:bq,a:ba,r:br};}const qs=getACQs();if(editIdx===null)qs.push(data);else qs[editIdx]=data;setACQs(qs);show('s-adm-cat');renderCatQs();}
function deleteQ(){if(!confirm('حذف هذا السؤال؟'))return;const qs=getACQs();qs.splice(editIdx,1);setACQs(qs);show('s-adm-cat');renderCatQs();}
function buildLL(){[0,1].forEach(ti=>{document.getElementById(`ll${ti+1}`).innerHTML=LL.map(l=>{const on=pll[ti].includes(l.id);return`<button onclick="tLL(${ti},'${l.id}')" style="border-radius:7px;padding:.32rem .08rem;cursor:pointer;font-family:'Cairo',sans-serif;font-size:.55rem;text-align:center;border:1.5px solid ${on?'#C9922A':'#E8D9B5'};background:${on?'#FFE8C9':'white'};color:#4A2A0A"><div style="font-size:.88rem">${l.ic}</div>${l.n}</button>`;}).join('');});}
function tLL(ti,lid){const a=pll[ti];if(a.includes(lid))pll[ti]=a.filter(x=>x!==lid);else if(a.length<3)pll[ti]=[...a,lid];document.getElementById(`c${ti+1}`).textContent=pll[ti].length;buildLL();}
function startGame(){teams=[{n:document.getElementById('t1n').value.trim()||"الفريق الأول",s:0,ll:pll[0].length===3?[...pll[0]]:["h","c","t"]},{n:document.getElementById('t2n').value.trim()||"الفريق الثاني",s:0,ll:pll[1].length===3?[...pll[1]]:["h","c","t"]}];used=new Set();turn=0;pickGQ();document.getElementById('btitle').textContent=document.getElementById('gname').value.trim()||"حسم — التحدي الإسلامي";buildBoard();show('s-board');}
function buildBoard(){const done=sel.every(c=>(gq[c]||[]).every((_,i)=>used.has(c+i)));if(done){showEnd();return;}document.getElementById('tbadge').textContent="دور: "+teams[turn].n;document.getElementById('bgrid').innerHTML=sel.map(cat=>{const d=CATS[cat],qs=gq[cat]||[];let dn=cat;if(d.isJuz){const j=juz[d.slot];dn=JUZ[j]?JUZ[j].name:`الجزء ${j}`;}const mb=(idx)=>{const key=cat+idx,ud=used.has(key),q=qs[idx];if(!q)return`<div class="pb ud">-</div>`;const pc=idx<2?'p2':idx<4?'p4':'p6';return ud?`<div class="pb ud">✓</div>`:`<div class="pb ${pc}" data-cat="${cat}" data-idx="${idx}">${q.p}</div>`;};return`<div class="bcard"><div class="bcard-hd">${dn}</div><div class="bcard-body"><div class="bside">${mb(0)}${mb(2)}${mb(4)}</div><div class="cimgw" style="background:${d.bg}"><img src="${d.ic}"></div><div class="bside">${mb(1)}${mb(3)}${mb(5)}</div></div></div>`;}).join('');document.getElementById('bgrid').onclick=e=>{const el=e.target.closest('[data-cat]');if(!el)return;openQ(el.dataset.cat,parseInt(el.dataset.idx));};buildSbar();}
function buildSbar(){document.getElementById('sbar').innerHTML=teams.map((t,i)=>`<div class="sb-team${turn===i?' active':''}"><div style="color:${turn===i?'#8B5A1A':'#A0826D'};font-weight:700;font-size:.7rem;margin-bottom:.12rem">${t.n}</div><div class="score-row"><button class="sbtn" onclick="adjS(${i},-50)">−</button><span class="snum" style="color:${turn===i?'#C05A20':'#8B5A1A'}" onclick="editS(${i})">${t.s}</span><button class="sbtn" onclick="adjS(${i},50)">+</button></div><div style="display:flex;gap:.2rem;justify-content:center;margin-top:.15rem">${t.ll.map(id=>{const l=LL.find(x=>x.id===id);return l?`<span style="font-size:.7rem">${l.ic}</span>`:''}).join('')}</div></div>`).join('');}
function adjS(i,d){teams[i].s=Math.max(0,teams[i].s+d);buildSbar();}
function editS(i){const v=prompt(`النقاط الحالية: ${teams[i].s}\nاكتب القيمة الجديدة:`,teams[i].s);if(v===null)return;const n=parseInt(v);if(!isNaN(n)&&n>=0){teams[i].s=n;buildSbar();}}
function openQ(cat,idx){const q=gq[cat][idx];cq={cat,idx,...q};phase='main';ms=null;document.getElementById('phasebanner').style.display='none';document.getElementById('qbadge').textContent=cat;document.getElementById('qbadge').style.background=idx<2?'#5A8E3D':idx<4?'#C05A20':'#9B2D2D';document.getElementById('qtext').textContent=q.q;document.getElementById('qans').style.display='none';document.getElementById('rbtn').style.display='inline-block';document.getElementById('jrow').style.display='none';document.getElementById('ppill').textContent=q.p+' نقطة';document.getElementById('qturn').textContent='دور: '+teams[turn].n;timer=q.p===200?30:q.p===400?45:90;startT();show('s-q');}
function startT(){clearInterval(tInt);updT();tInt=setInterval(()=>{timer--;updT();if(timer<=0)clearInterval(tInt);},1000);}
function updT(){const max=phase==='bonus'?30:(cq.p===200?30:cq.p===400?45:90);const col=timer>max*.5?'#5A8E3D':timer>max*.25?'#C05A20':'#9B2D2D';document.getElementById('tpill').textContent='⏱ '+String(Math.floor(timer/60)).padStart(2,'0')+':'+String(timer%60).padStart(2,'0');document.getElementById('tbar').style.width=(timer/max*100)+'%';document.getElementById('tbar').style.background=col;}
function revealAns(){clearInterval(tInt);const src=phase==='bonus'?cq.bo:cq;document.getElementById('atext').textContent=src.a;document.getElementById('rtext').textContent=src.r;document.getElementById('stext').textContent='المصدر: '+(src.s||cq.s||'');document.getElementById('qans').style.display='block';document.getElementById('rbtn').style.display='none';buildJB();}
function buildJB(){document.getElementById('jrow').style.display='flex';document.getElementById('jprompt').textContent=phase==='main'?'من أجاب صح؟':`هل أجاب ${teams[ms].n} صح؟`;if(phase==='main'){document.getElementById('jbtns').innerHTML=teams.map((t,i)=>`<button onclick="jMain(${i})" style="flex:1;background:#5A8E3D;color:white;border:none;border-radius:8px;padding:.58rem;font-family:'Cairo',sans-serif;font-weight:700;cursor:pointer;font-size:.78rem">${t.n}</button>`).join('')+`<button onclick="jMain(-1)" style="flex:1;background:white;color:#A0826D;border:1.5px solid #E8D9B5;border-radius:8px;padding:.58rem;font-family:'Cairo',sans-serif;font-weight:700;cursor:pointer;font-size:.78rem">ولا أحد</button>`;}else{document.getElementById('jbtns').innerHTML=`<button onclick="jBonus(true)" style="flex:1;background:#5A8E3D;color:white;border:none;border-radius:8px;padding:.58rem;font-family:'Cairo',sans-serif;font-weight:700;cursor:pointer;font-size:.78rem">نعم +١٠٠</button><button onclick="jBonus(false)" style="flex:1;background:#9B2D2D;color:white;border:none;border-radius:8px;padding:.58rem;font-family:'Cairo',sans-serif;font-weight:700;cursor:pointer;font-size:.78rem">لا، الفريق الآخر</button>`;}}
function jMain(idx){if(idx>=0)teams[idx].s+=cq.p;if(cq.bo&&idx>=0){phase='bonus';ms=idx;document.getElementById('phasebanner').style.display='block';document.getElementById('qbadge').textContent='سؤال إضافي';document.getElementById('qbadge').style.background='#D4A843';document.getElementById('qtext').textContent=cq.bo.q;document.getElementById('qans').style.display='none';document.getElementById('rbtn').style.display='inline-block';document.getElementById('jrow').style.display='none';document.getElementById('ppill').textContent='+١٠٠';timer=30;startT();return;}finQ();}
function jBonus(ok){if(ok){teams[ms].s+=100;finQ();return;}const o=1-ms;document.getElementById('jprompt').textContent=`هل أجاب ${teams[o].n} صح؟`;document.getElementById('jbtns').innerHTML=`<button onclick="jBonusO(true)" style="flex:1;background:#5A8E3D;color:white;border:none;border-radius:8px;padding:.58rem;font-family:'Cairo',sans-serif;font-weight:700;cursor:pointer;font-size:.78rem">نعم +١٠٠</button><button onclick="jBonusO(false)" style="flex:1;background:#9B2D2D;color:white;border:none;border-radius:8px;padding:.58rem;font-family:'Cairo',sans-serif;font-weight:700;cursor:pointer;font-size:.78rem">لا، انتقل</button>`;}
function jBonusO(ok){if(ok)teams[1-ms].s+=100;finQ();}
function finQ(){used.add(cq.cat+cq.idx);turn=1-turn;cq=null;phase='main';ms=null;document.getElementById('phasebanner').style.display='none';buildBoard();show('s-board');}
function backBoard(){clearInterval(tInt);cq=null;phase='main';document.getElementById('phasebanner').style.display='none';buildBoard();show('s-board');}
function showEnd(){const w=teams[0].s!==teams[1].s?(teams[0].s>teams[1].s?teams[0]:teams[1]):null;document.getElementById('wname').innerHTML=w?`🏆 الفائز: ${w.n} — ${w.s} نقطة`:`🤝 تعادل!`;document.getElementById('fcards').innerHTML=teams.map(t=>`<div style="text-align:center;background:white;border:${w&&w.n===t.n?'2.5px solid #C9922A':'1.5px solid #E8D9B5'};border-radius:13px;padding:.9rem 1.4rem;min-width:110px"><div style="color:#8B5A1A;font-size:.75rem;margin-bottom:.25rem">${t.n}</div><div style="color:${w&&w.n===t.n?'#C05A20':'#8B5A1A'};font-size:2.2rem;font-weight:900;line-height:1">${t.s}</div><div style="color:#A0826D;font-size:.68rem;margin-top:.15rem">نقطة</div>${w&&w.n===t.n?'<div style="color:#C9922A;font-size:.88rem;margin-top:.35rem">🥇 الفائز</div>':''}</div>`).join('');show('s-end');}
function resetGame(){sel=[];pll=[[],[]];used=new Set();turn=0;juz={1:null,2:null};gq={};teams=[];document.getElementById('t1n').value='';document.getElementById('t2n').value='';document.getElementById('gname').value='';buildLL();document.getElementById('c1').textContent=0;document.getElementById('c2').textContent=0;show('s-home');buildGrid();}
buildGrid();buildLL();
